#!/usr/bin/env bash
# continuous-discovery.sh — Continuous Discovery（持续探索） SOP walkthrough for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
WORKFLOW="Continuous Discovery（持续探索）"

usage() {
  cat <<EOF
continuous-discovery.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./continuous-discovery.sh             # interactive
  ./continuous-discovery.sh --dry-run
  ./continuous-discovery.sh --json
  ./continuous-discovery.sh --explain
  ./continuous-discovery.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Continuous Discovery（持续探索）" 工作流。

一句话: 从「项目制、瀑布式的一次性研究」到「团队每周与客户接触的持续节奏」，让产品决策始终绑在最新证据上。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定 desired outcome（业务结果）**: 锁定一个可度量的产品结果作为 OST 根。跳过→discovery 漫无目的，访谈拿一堆无关洞察。 (evidence: [T03-S001])"
  "**建 OST**: 把 outcome → 机会（用户需求/痛点）→ 解决方案 → 实验，可视化连接。跳过→隐含假设不外显，团队各想各的。 (evidence: [T03-S001])"
  "**每周访谈节奏**: 每周固定与 1+ 客户做小型接触（不是攒到季度做大研究）。跳过→证据陈旧，回到拍脑袋。 (evidence: [T03-S002])"
  "**嵌入式合成**: 几次访谈后就更新 OST，让树始终基于证据而非愿望。跳过→OST 变成一次性海报，与现实脱节。 (evidence: [T03-S001])"
  "**小实验验证假设**: 拆小机会→小方案→快实验。跳过→直接造大功能，赌注大、反馈慢。 (evidence: [T03-S001, T03-S024])"
)
declare -a FAILURE_MODES=(
  "OST 当一次性海报: 画完挂墙不更新。**规定每几次访谈就更新 OST，否则它与现实脱节。** (evidence: [T03-S001])"
  "没有真人每周节奏: 退回季度大研究。**把每周客户接触排进日历当固定仪式，没素材也要触达。** (evidence: [T03-S002])"
  "直接跳到大方案: 跳过机会拆解直接造大功能。**先把大机会拆成可快速测的小机会再做。** (evidence: [T03-S001])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "continuous-discovery-walkthrough"
fi
